import React, { useEffect, useState } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const clientSecret = 'YOUR_CLIENT_SECRET';
const redirectUri = 'YOUR_REDIRECT_URI';
const authServer = 'YOUR_AUTH_SERVER';
const tokenEndpoint = 'YOUR_TOKEN_ENDPOINT';
const localStorageTokenKey = 'access_token';

const App = () => {
  const [authCode, setAuthCode] = useState(null);
  const [accessToken, setAccessToken] = useState(localStorage.getItem(localStorageTokenKey));

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    if (code) {
      setAuthCode(code);
    }
  }, []);

  useEffect(() => {
    if (authCode) {
      fetch(tokenEndpoint, {
        method: 'POST',
        body: JSON.stringify({
          "grant_type": "authorization_code",
          "client_id": clientId,
          "client_secret": clientSecret,
          "redirect_uri": redirectUri,
          "code": authCode
        }),
        headers: {
          'Content-Type': 'application/json'
        },
      }).then(res => res.json())
        .then(data => {
          localStorage.setItem(localStorageTokenKey, data.access_token);
          setAccessToken(data.access_token);
        }).catch(error => console.error(error));
    }
  }, [authCode]);

  const authenticate = () => {
    window.location.href = `${authServer}/authorize?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}`;
  };

  if (!accessToken) {
    return (
      <button onClick={authenticate}>Login</button>
    );
  }

  return (
    <div>
      <h1>Successfully authenticated</h1>
      <p>Your Access Token: {accessToken}</p>
    </div>
  );
};

export default App;